#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10,M=4e5+10;

int n,m;
int head[N],ver[M],nxt[M],tot=1;
int dfn[N],low[N],num,stk[N],top,now;
int root,sz,s[N<<1];
long long sum,ans;
vector<int> g[N<<1];

void add(int u,int v){
    ver[++tot]=v,nxt[tot]=head[u],head[u]=tot;
}

void tarjan(int x){
    dfn[x]=low[x]=++num;
    stk[++top]=x,sz++;
    for(int i=head[x],y;i;i=nxt[i])
        if(!dfn[y=ver[i]]){
            tarjan(y);
            low[x]=min(low[x],low[y]);
            if(low[y]>=dfn[x]){
                now++;
                int z;
                do{
                    z=stk[top--];
                    g[now].push_back(z),g[z].push_back(now);
                    //printf("add: %d %d\n",z,now);
                }while(z!=y);
				g[now].push_back(x),g[x].push_back(now);
                //printf("add: %d %d\n",x,now);
            }
        }else
            low[x]=min(low[x],dfn[y]);
}

void dfs1(int x,int fa){
    s[x]=(x<=n);
    for(int y:g[x])
        if(y!=fa){
            dfs1(y,x);
            s[x]+=s[y];
        }
    if(x<=n)
        sum-=s[x];
    else
        sum+=1LL*g[x].size()*s[x];
}

void dfs2(int x,int fa){
    if(x<=n){
        ans+=sum+s[x]-sz+1;
        //printf("val: %d %lld\n",x,sum+s[x]-sz+1);
    }
    for(int y:g[x])
        if(y!=fa){
            if(x<=n)
                sum+=s[x],sum-=sz-s[y];
            else
                sum-=1LL*g[x].size()*s[x],sum+=1LL*g[x].size()*(sz-s[y]);
            dfs2(y,x);
            if(x<=n)
                sum-=s[x],sum+=sz-s[y];
            else
                sum+=1LL*g[x].size()*s[x],sum-=1LL*g[x].size()*(sz-s[y]);
        }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        add(u,v);
        add(v,u);
    }
    now=n;
    for(int i=1;i<=n;i++)
        if(!dfn[i]){
            root=i,sz=sum=0;
            tarjan(root);
            //printf("%d\n",sz); 
            dfs1(root,0);
            dfs2(root,0);
        }
    printf("%lld",ans);
    return 0;
}
